#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct {
  float weight;
  long assign;  
  float cost;  
} Point_Struct;

__attribute__((reqd_work_group_size(256, 1, 1)))
void pgain_kernel(
    global const Point_Struct* p,
    global const float* coord,
    global float* work_mem,
    global const int* center_table,
    global char* switch_membership,
    local float* local_coord,
    const int num,
    const int dim,
    const long x,
    const int K)
{
  int i = get_global_id(0);
  int tid = get_local_id(0);

  if (i >= num) return;

  // Load coordinates into local memory
  for (int d = tid; d < dim; d += 256) {
    local_coord[d] = coord[d * num + x];
  }
  barrier(CLK_LOCAL_MEM_FENCE);

  // Compute distance from point i to point x
  float x_cost = 0.0f;
  for (int d = 0; d < dim; d++) {
    float diff = coord[d * num + i] - local_coord[d];
    x_cost += diff * diff;
  }
  x_cost *= p[i].weight;

  float current_cost = p[i].cost;

  if (x_cost < current_cost) {
    switch_membership[i] = 1;
    work_mem[i * (K + 1) + K] += x_cost - current_cost;
  } else {
    int assign = p[i].assign;
    int ct = center_table[assign];
    work_mem[ct] += current_cost - x_cost;
  }
}

__attribute__((reqd_work_group_size(256, 1, 1)))
void pgain_kernel_center(
    global const Point_Struct* p,
    global const float* coord,
    global float* work_mem,
    global const int* center_table,
    global const char* switch_membership,
    global const int* is_center,
    local float* local_sum,
    const int num,
    const int dim,
    const long x,
    const int K,
    const float z,
    const int nproc)
{
  int i = get_global_id(0);
  int tid = get_local_id(0);

  if (i >= num) return;

  if (is_center[i]) {
    int ct = center_table[i];
    float low = z;

    // Sum across all processors
    for (int p = 0; p < nproc; p++) {
      low += work_mem[ct + p * (K + 1)];
    }

    work_mem[num * (K + 1) + ct] = low;

    if (low > 0) {
      work_mem[i * (K + 1) + K] -= low;
    }
  }
}
